//pendiente por configurar
import { useState } from "react";
import {
  BotonTema,
  Header2,
  Footer,
  Github,
} from "../reutilizables/componentes";

function NuevoRegistro() {
  const [turno, setturno] = useState("");
  const [fecha, setfecha] = useState("");
  const [proveedorR, setproveedorR] = useState("");
  const [loteR, setloteR] = useState("");
  const [canecas20, setcanecas20] = useState("");
  const [canecas60, setcanecas60] = useState("");
  const [cdRecibidas, setcdRecibidas] = useState("");
  const [caRecibidas, setcaRecibidas] = useState("");
  const [cdEntregadas, setcdEntregadas] = useState("");
  const [caEntregadas, setcaEntregadas] = useState("");
  const [listaBaches, setlistaBaches] = useState([]);
  const [proveedor, setproveedor] = useState("");
  const [lote, setlote] = useState("");
  const [canecas, setcanecas] = useState("");

  const handleRegistrarBache = () => {
    if (proveedor === "vacio" || !lote || !canecas) {
      alert("faltaron campos requeridos, intente de nuevo");
      return;
    }
    const nuevoBache = { proveedor, lote, canecas };
    setlistaBaches([...listaBaches, nuevoBache]);
    setproveedor("vacio");
    setlote("");
    setcanecas("");
  };

  const handleEliminarBache = () => {
    const copiaBaches = [...listaBaches];
    copiaBaches.pop();
    setlistaBaches(copiaBaches);
  };

  const HacerRegistro = async () => {
    try {
      if (
        !turno ||
        !fecha ||
        !proveedorR ||
        !loteR ||
        !canecas20 ||
        !canecas60 ||
        !cdRecibidas ||
        !caRecibidas ||
        !cdEntregadas ||
        !caEntregadas ||
        listaBaches.length === 0
      ) {
        alert("Porfavor, debe llenar todos los campo requeridos");
        return;
      }

      if (
        !window.confirm(
          "¿Estas seguro de enviar estos datos? verifica de nuevo si consideras necesario",
        )
      ) {
        return;
      }

      listaBaches = Array.from(listaBaches);

      const res = await fetch("http://localhost:4000/api/crearRegistro", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          turno: turno,
          fecha: fecha,
          proveedorR: proveedorR,
          loteR: loteR,
          canecas20: canecas20,
          canecas60: canecas60,
          cdRecibidas: cdRecibidas,
          caRecibidas: caRecibidas,
          cdEntregadas: cdEntregadas,
          caEntregadas: caEntregadas,
          listaBaches: listaBaches,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error || "Error al crear registro");
        return;
      }
      alert("Registro creado exitosamente");
      setturno("");
      setfecha("");
      setproveedorR("");
      setloteR("");
      setcanecas20("");
      setcanecas60("");
      setcdRecibidas("");
      setcaRecibidas("");
      setcdEntregadas("");
      setcaEntregadas("");
      setlistaBaches([]);
    } catch (error) {
      alert("Error al crear el usuario: error de conexión con el servidor");
    }
  };

  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={() => window.history.back()}>
            volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <select
            id="turno"
            onChange={(e) => setturno(e.target.value)}
            value={turno}
          >
            <option value={""}>-- seleccione su turno</option>
            <option value={"Turno 1"}>Turno 1</option>
            <option value={"Turno 2"}>Turno 2</option>
          </select>
          <label>
            Ingrese la Fecha:
            <input
              type="date"
              placeholder="Ingrese la fecha"
              value={fecha}
              onChange={(e) => setfecha(e.target.value)}
            ></input>
          </label>
          <input
            type="text"
            id="proveedorRinde"
            placeholder="Proveedor de rinde"
            value={proveedorR}
            onChange={(e) => setproveedorR(e.target.value)}
          ></input>
          <input
            type="number"
            id="loteRinde"
            placeholder="Lote del Rinde"
            value={loteR}
            onChange={(e) => setloteR(e.target.value)}
          ></input>
          <input
            type="number"
            id="canecas20"
            placeholder="Canecas de Rinde 20L"
            value={canecas20}
            onChange={(e) => setcanecas20(e.target.value)}
          ></input>
          <input
            type="number"
            id="canecas60"
            placeholder="Canecas de Rinde 60L"
            value={canecas60}
            onChange={(e) => setcanecas60(e.target.value)}
          ></input>
          <input
            type="number"
            id="canecasInicioD"
            placeholder="Canecas descogadas recibidas"
            value={cdRecibidas}
            onChange={(e) => setcdRecibidas(e.target.value)}
          ></input>
          <input
            type="number"
            id="agitadasInicio"
            placeholder="canecas agitadas recibidas"
            value={caRecibidas}
            onChange={(e) => setcaRecibidas(e.target.value)}
          ></input>
          <input
            type="number"
            id="canecasFinalD"
            placeholder="Canecas entregadas al otro turno"
            value={cdEntregadas}
            onChange={(e) => setcdEntregadas(e.target.value)}
          ></input>
          <input
            type="number"
            id="agitadasFinal"
            placeholder="Canecas agitadas entregadas"
            value={caEntregadas}
            onChange={(e) => setcaEntregadas(e.target.value)}
          ></input>

          <section id="registroBaches">
            <p>Ingrese los datos de cada bache:</p>

            <select
              id="proveedorBache"
              onChange={(e) => setproveedor(e.target.value)}
              value={proveedor}
            >
              <option value={"vacio"}>-- seleccione proveedor</option>
              <option value={"RR"}>RR</option>
              <option value={"SBQ"}>SBQ</option>
              <option value={"STA"}>STA</option>
              <option value={"SMJ"}>SMJ</option>
              <option value={"SM"}>SM</option>
              <option value={"CHT"}>CHT</option>
            </select>

            <input
              type="number"
              id="loteBache"
              placeholder="Lote del bache"
              value={lote}
              onChange={(e) => setlote(e.target.value)}
            ></input>

            <input
              type="number"
              id="canecasBache"
              placeholder="Canecas del bache"
              value={canecas}
              onChange={(e) => setcanecas(e.target.value)}
            ></input>

            <button
              id="añadir"
              className="principales"
              onClick={handleRegistrarBache}
            >
              añadir
            </button>
            <button
              id="eliminarBache"
              className="secundarios"
              onClick={handleEliminarBache}
            >
              Eliminar ultimo bache
            </button>

            <ul className="listas">
              <h4>lista de baches: </h4>
              {listaBaches.map((bache, index) => (
                <li key={index}>
                  Proveedor: {bache.proveedor}
                  <br />
                  Lote: {bache.lote}
                  <br />
                  Numero de canecas: {bache.canecas}
                  {""}
                </li>
              ))}
            </ul>
          </section>
          <button
            id="registrar"
            className="principales"
            onClick={HacerRegistro}
          >
            registrar informacion
          </button>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}
export default NuevoRegistro;
